#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
ll l,r,k,len,num[25],dp[25][15];
/*
x  第几位 从个位到高位（dfs是从高位到个位的）
pre 上一个数字 
limit 是否受到最大值的限制 
beg0 （1代表前面出现过非0数字 ，0代表前面全是前导0） 
*/
ll dfs(ll x,ll pre,ll limit,ll beg0)
{
	if(!x) return 1;
	if((!limit)&&beg0&&(dp[x][pre]!=-1)) return dp[x][pre];
	int mx=(limit)?num[x]:9;
	ll cnt=0;
	for(int i=0;i<=mx;i++)
	{
		if((!beg0)||abs(i-pre)<=k)
		{
			cnt+=dfs(x-1,i,limit&&(i==mx),beg0||i);
		}
	}
	if((!limit)&&beg0) dp[x][pre]=cnt;
	return cnt;
}
ll solve(ll x)
{
//	int len;
	for(len=1;x;x/=10,len++)
	{
		num[len]=x%10;
	}
	return dfs(len-1,0,1,0);//这里pre随便选一个数就行 
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	memset(dp,-1,sizeof(dp));
	cin>>l>>r>>k;
	cout<<solve(r)-solve(l-1);
	return 0;
}
